// ─── Types ───────────────────────────────────────────────────────────────────

interface MeasureDetail {
                        name: string;
                        score: number;
                        status: 'EXCELLENT' | 'HEALTHY' | 'WARNING' | 'HIGH_RISK' | 'CRITICAL';
                        value_label: string;
                        details: string;
}

interface CategoryDetail {
                        score: number;
                        status: string;
                        grade: string;
                        measures: MeasureDetail[];
}

interface CategorizedHealthReport {
                        architecture_health: CategoryDetail;
                        code_quality: CategoryDetail;
                        technical_debt: CategoryDetail;
                        reliability: CategoryDetail;
                        knowledge_health: CategoryDetail;
                        performance_readiness: CategoryDetail;
                        security_readiness: CategoryDetail;
                        scalability: CategoryDetail;
                        maintainability: CategoryDetail;
                        developer_experience: CategoryDetail;
}

interface HealthForecastPoint {
                        days: number;
                        label: string;
                        score: number;
}

interface HealthForecast {
                        current_score: number;
                        predictions: HealthForecastPoint[];
                        reason?: string;
                        reasons?: string[];
                        expected_after_improvements?: number;
}

interface DimensionScore {
                        name: string;
                        score: number;
                        weight: number;
                        grade: string;
                        trend: 'up' | 'down' | 'stable';
                        trend_delta: number;
                        icon: string;
                        color: string;
                        explanation: string;
                        source: string;
}

interface HealthAction {
                        rank: number;
                        title: string;
                        description: string;
                        dimension: string;
                        expected_improvement: number;
                        effort: string;
                        link_path: string;
                        severity: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
}

interface HealthTrendPoint {
                        snapshot_id: number;
                        timestamp: string;
                        overall_score: number;
                        grade: string;
                        dimension_scores: Record<string, number>;
}

interface RecommendationResponse {
                        recommendation: string;
                        improvement: number;
                        priority: string;
                        estimated_effort: string;
}

interface ExecutiveResponse {
                        repository_health: number;
                        engineering_velocity: string;
                        risk: string;
                        deployment_readiness: string;
                        knowledge_risk: string;
                        technical_debt: string;
                        future_health: string;
}

interface CtoResponse {
                        critical_issues: string[];
                        top_opportunities: string[];
                        architecture_drift: string;
}

interface HealthIntelligenceReport {
                        repo_id: string;
                        snapshot_id?: number;
                        generated_at: string;
                        overall_score: number;
                        grade: string;
                        status: string;
                        status_color: string;
                        score_delta: number;
                        trend: string;
                        headline: string;
                        narrative: string;
                        what_is_healthy: string[];
                        what_needs_attention: string[];
                        dimensions: DimensionScore[];
                        priority_actions: HealthAction[];
                        trend_history: HealthTrendPoint[];
                        categories?: CategorizedHealthReport;
                        forecast?: HealthForecast;
                        recommendations?: RecommendationResponse[];
                        executive?: ExecutiveResponse;
                        cto?: CtoResponse;
}

